args.sparql:
SELECT ?actress ?actressLabel WHERE {
  wd:Q3222 p:P161 [ ps:P161 wd:Q40229 ] ;
               wdt:P577 ?releaseDate.
  FILTER(YEAR(?releaseDate) >= 1940 && YEAR(?releaseDate) <= 1949).
  ?film wdt:P161 wd:Q3222.
  ?film p:P161 [ ps:P161 wd:Q40229 ; pq:P21 wd:Q6581072 ].
  ?actress (ps:P161|wdt:P161) wd:Q40229.
  ?actress wdt:P21 wd:Q6581072.
  OPTIONAL { ?actress rdfs:label ?actressLabel FILTER (LANG(?actressLabel) = 'en') }
}

SELECT DISTINCT ?actress ?actressLabel WHERE {
  ?film wdt:P161 wd:Q3222 ;
         wdt:P577 ?releaseDate ;
         wdt:P161 ?actress.
  FILTER(YEAR(?releaseDate) >= 1940 && YEAR(?releaseDate) <= 1949).
  ?actress wdt:P21 wd:Q6581072.
  OPTIONAL { ?actress rdfs:label ?actressLabel FILTER (LANG(?actressLabel) = 'en') }
}

SELECT DISTINCT ?actress ?actressLabel WHERE {
  ?film wdt:P161 wd:Q40229 ;
         wdt:P577 ?releaseDate .
  FILTER(YEAR(?releaseDate) >= 1940 && YEAR(?releaseDate) <= 1949) .
  ?film wdt:P161 ?actress .
  ?actress wdt:P21 wd:Q6581072 .
  FILTER(?actress != wd:Q40229) .
  OPTIONAL { ?actress rdfs:label ?actressLabel FILTER (LANG(?actressLabel) = 'en') }
}

